function app_render_page($title, $body, array $options = [])
{
    $flash = app_flash_get();
    $showNav = !isset($options['show_nav']) || $options['show_nav'] !== false;
    $nav = '';
    if ($showNav) {
        $nav = '<header class="topbar"><div class="brand">GPT OIDC</div><nav class="topnav"><a href="/">总览</a><a href="/flow-demo">流程演示</a><a href="/ui-kit">界面预览</a><a href="/sso">SSO 登录</a><a href="/admin">管理后台</a></nav></header>';
    }

    $flashHtml = '';
    if ($flash) {
        $flashHtml = '<div class="alert ' . app_h($flash['type']) . '"><div>' . app_h($flash['message']) . '</div></div>';
    }

    if (function_exists('app_close_session')) {
        app_close_session();
    }

    http_response_code(isset($options['status']) ? (int) $options['status'] : 200);
    header('Content-Type: text/html; charset=utf-8');

    echo '<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>' . app_h($title) . '</title><style>
    :root{--bg:#081120;--panel:#0f1b31;--panel-2:#13223d;--line:#2b4268;--text:#e5eefc;--muted:#91a4c6;--blue:#4f8cff;--cyan:#3cc7d9;--green:#16a34a;--red:#dc2626;--amber:#f59e0b;--shadow:0 24px 60px rgba(2,8,23,.45)}
    *{box-sizing:border-box}body{margin:0;font-family:Inter,Segoe UI,Arial,sans-serif;background:radial-gradient(circle at top left,#0b1730 0,#081120 45%,#050b16 100%);color:var(--text)}a{color:#8ab4ff;text-decoration:none}a:hover{text-decoration:underline}.shell{max-width:1220px;margin:0 auto;padding:24px}.topbar{display:flex;justify-content:space-between;align-items:center;gap:16px;padding:18px 20px;border:1px solid var(--line);border-radius:22px;background:rgba(15,27,49,.75);backdrop-filter:blur(14px);box-shadow:var(--shadow);margin-bottom:22px}.brand{font-weight:800;letter-spacing:.08em;text-transform:uppercase}.topnav{display:flex;gap:14px;flex-wrap:wrap}.hero{padding:28px;border:1px solid var(--line);border-radius:28px;background:linear-gradient(140deg,rgba(79,140,255,.16),rgba(60,199,217,.08) 45%,rgba(15,27,49,.88));box-shadow:var(--shadow);margin-bottom:20px}.hero h1{margin:0 0 10px;font-size:34px;line-height:1.15}.hero p{margin:0;color:var(--muted);max-width:820px;line-height:1.7}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:18px}.card{background:linear-gradient(180deg,rgba(19,34,61,.97),rgba(10,19,35,.97));border:1px solid var(--line);border-radius:22px;padding:22px;box-shadow:var(--shadow);margin-bottom:18px}.card h2,.card h3{margin:0 0 12px}.card p{color:var(--muted);line-height:1.7}.metric{font-size:28px;font-weight:800;margin-top:6px}.muted{color:var(--muted)}.badge{display:inline-block;padding:6px 10px;border-radius:999px;border:1px solid var(--line);background:rgba(79,140,255,.08);font-size:12px;letter-spacing:.04em;text-transform:uppercase}.list{display:grid;gap:10px}.list .row{padding:12px 14px;border-radius:14px;background:rgba(8,17,32,.65);border:1px solid rgba(43,66,104,.6)}.steps{display:grid;gap:12px;counter-reset:step}.step{display:grid;grid-template-columns:40px 1fr;gap:14px;align-items:start;padding:14px;border-radius:16px;background:rgba(8,17,32,.7);border:1px solid rgba(43,66,104,.7)}.step:before{counter-increment:step;content:counter(step);display:grid;place-items:center;width:40px;height:40px;border-radius:14px;background:linear-gradient(180deg,var(--blue),#265fd8);font-weight:800}.alert{padding:14px 16px;border-radius:18px;margin-bottom:18px;border:1px solid transparent}.alert.success{background:rgba(22,163,74,.16);border-color:rgba(22,163,74,.4)}.alert.error{background:rgba(220,38,38,.15);border-color:rgba(220,38,38,.35)}.alert.info{background:rgba(79,140,255,.16);border-color:rgba(79,140,255,.35)}form{display:block}.form-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:16px}.stack{display:grid;gap:14px}.field{display:grid;gap:6px}.field label{font-size:13px;color:#d4def0;font-weight:600}.hint{font-size:12px;color:var(--muted)}input,select,textarea,button{width:100%;border-radius:14px;border:1px solid #35507e;background:#06101f;color:var(--text);padding:13px 14px;font:inherit}textarea{min-height:110px;resize:vertical}button,.button-link{cursor:pointer;background:linear-gradient(180deg,#4f8cff,#2563eb);border:1px solid #4f8cff;font-weight:700;box-shadow:0 12px 28px rgba(37,99,235,.35);display:inline-flex;align-items:center;justify-content:center;gap:8px;text-decoration:none;color:#fff}.button-link:hover{text-decoration:none}.secondary,.button-link.secondary{background:#10213f;border-color:#34517e;box-shadow:none}.warn,.button-link.warn{background:linear-gradient(180deg,#ef4444,#b91c1c);border-color:#ef4444}.inline,.button-link.inline{width:auto;padding:10px 14px}.actions{display:flex;gap:12px;flex-wrap:wrap;align-items:center}.mono{font-family:Consolas,Monaco,monospace}.table-wrap{overflow:auto;border-radius:18px;border:1px solid rgba(43,66,104,.6)}table{width:100%;border-collapse:collapse;min-width:860px;background:rgba(8,17,32,.45)}th,td{padding:13px 14px;text-align:left;border-bottom:1px solid rgba(43,66,104,.55);vertical-align:top}th{font-size:12px;letter-spacing:.05em;text-transform:uppercase;color:#a7b8d6;background:rgba(8,17,32,.92)}td{font-size:14px}.small{font-size:12px;color:var(--muted)}.code-panel{padding:16px;border-radius:18px;background:#050d18;border:1px solid #243a5f}.footer-note{padding:18px 0 30px;color:var(--muted);font-size:13px}.center-shell{max-width:840px;margin:0 auto;padding:28px 20px}.install-hero{padding:24px;border-radius:24px;background:linear-gradient(150deg,rgba(22,163,74,.14),rgba(79,140,255,.12));border:1px solid var(--line);box-shadow:var(--shadow);margin-bottom:20px}.split{display:grid;grid-template-columns:1.15fr .85fr;gap:18px}.flow-line{display:grid;gap:12px}.pill{display:inline-flex;align-items:center;gap:8px;padding:6px 12px;border-radius:999px;background:rgba(60,199,217,.09);border:1px solid rgba(60,199,217,.35);font-size:12px}.section-title{display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:16px}.section-title h2,.section-title h3{margin:0}.kpi{padding:16px;border-radius:18px;background:rgba(8,17,32,.62);border:1px solid rgba(43,66,104,.6)}@media (max-width:900px){.split{grid-template-columns:1fr}.topbar{align-items:flex-start;flex-direction:column}.hero h1{font-size:28px}}</style></head><body><div class="shell">' . $nav . $flashHtml . $body . '<div class="footer-note">Lightweight ChatGPT Business OIDC provider with card activation, install wizard, admin UI, and OpenAI redirect bridge.</div></div></body></html>';
    exit;
}

function app_home_html(array $lookup = [])
{
    $configured = app_is_configured() ? '已配置' : '需要安装';
    $installLink = app_is_configured() ? '' : '<div class="actions" style="margin-top:18px"><a class="button-link inline" href="/install">打开安装向导</a></div>';
    $lookupCardValue = !empty($lookup['card_key']) ? ' value="' . app_h($lookup['card_key']) . '"' : '';
    $lookupResultHtml = '';
    if (!empty($lookup['email'])) {
        $lookupResultHtml = '<div class="alert success">已绑定邮箱：<strong>' . app_h($lookup['email']) . '</strong></div>';
    } elseif (!empty($lookup['card_key'])) {
        $lookupResultHtml = '<div class="alert info">已完成查询，这张卡当前没有可显示的已绑定邮箱。</div>';
    }

    return '<section class="hero"><span class="badge">' . app_h($configured) . '</span><h1>ChatGPT Business OIDC 身份系统</h1><p>本系统使用单页 SSO 卡密登录。用户输入卡密和邮箱前缀，系统再组合成允许的邮箱后缀，并通过标准 OIDC 授权码流程把用户跳回 OpenAI。</p>' . $installLink . '</section><section class="grid"><div class="card"><div class="section-title"><h3>当前能力</h3></div><div class="list"><div class="row">批量生成卡密并一次性导出 CSV</div><div class="row">单页 SSO 卡密登录，支持邮箱前缀 + 后缀</div><div class="row">首次自动绑定卡密与邮箱</div><div class="row">支持 OIDC Discovery、JWKS、Authorize、Token、Userinfo</div></div></div><div class="card"><div class="section-title"><h3>首页卡密查询</h3></div><p>输入卡密即可查看这张卡当前绑定到了哪个邮箱。未注册或未绑定的卡不会显示邮箱。</p><form method="get" action="/" class="stack"><input type="hidden" name="lookup" value="1"><div class="field"><label>卡密</label><input class="mono" type="text" name="card_key" placeholder="AB12CD-EF34GH-IJ56KL-MN78OP" required' . $lookupCardValue . '></div><div class="actions"><button type="submit">查询绑定邮箱</button></div></form>' . $lookupResultHtml . '</div><div class="card"><div class="section-title"><h3>OpenAI 对接说明</h3></div><p>本系统专门面向 <strong>ChatGPT Business</strong>。Business 的 SSO 只作用于 ChatGPT，不覆盖 API Platform，也不提供 SCIM。联调期间请把 OpenAI 侧 SSO 保持为 <strong>Optional</strong>。</p></div><div class="card"><div class="section-title"><h3>快捷入口</h3></div><div class="actions"><a class="button-link inline" href="/flow-demo">OIDC 流程演示</a><a class="button-link inline secondary" href="/ui-kit">HTML 界面参考</a><a class="button-link inline secondary" href="/sso">SSO 卡密登录</a></div></div></section>';
}

function app_flow_demo_html()
{
    return '<section class="hero"><span class="pill">浏览器可见跳转 + 后台令牌兑换</span><h1>OIDC 登录与兑换流程</h1><p>这个页面展示的是 OpenAI 跳转到你这里之后，用户在浏览器里真正会经历的流程。浏览器负责卡密验证和确认，OpenAI 随后会在后台调用 <code>/token</code> 完成兑换。</p></section><section class="split"><div class="card"><div class="section-title"><h3>用户路径</h3></div><div class="steps"><div class="step"><div><strong>用户先在 ChatGPT 输入受控邮箱</strong><br><span class="muted">用户先在 ChatGPT Business 里输入完整邮箱，邮箱后缀必须属于你配置的受控后缀。</span></div></div><div class="step"><div><strong>OpenAI 发起授权请求</strong><br><span class="muted">OpenAI 会跳转到 <code>/authorize</code>，并带上 <code>client_id</code>、<code>redirect_uri</code>、<code>state</code>、<code>nonce</code>、PKCE 等参数，有时还会带 <code>login_hint</code>。</span></div></div><div class="step"><div><strong>用户验证卡密和邮箱前缀</strong><br><span class="muted">系统只要求用户输入卡密和邮箱前缀，并校验它是否与 OpenAI 登录邮箱一致。</span></div></div><div class="step"><div><strong>确认桥接页</strong><br><span class="muted">系统展示一个确认页，告诉用户即将返回 OpenAI。</span></div></div><div class="step"><div><strong>带授权码跳回 OpenAI</strong><br><span class="muted">浏览器带着 <code>code</code> 和 <code>state</code> 回到 OpenAI。</span></div></div><div class="step"><div><strong>后台完成令牌兑换</strong><br><span class="muted">OpenAI 在后台调用 <code>/token</code>，再读取 <code>id_token</code> 和 <code>/userinfo</code>。</span></div></div></div></div><div class="card"><div class="section-title"><h3>流程示意</h3></div><div class="code-panel mono">用户 -> chatgpt.com\nchatgpt.com -> /authorize\n/authorize -> /sso（卡密 + 邮箱前缀）\n/sso -> /authorize?resume=1\n/authorize/approve -> redirect_uri?code=...&state=...\nOpenAI 后台 -> /token\nOpenAI 后台 -> /userinfo（可选）</div><p class="small">真实桥接页就是授权确认后的那个自动跳回页面。</p></div></section>';
}

function app_ui_kit_html()
{
    return '<section class="hero"><span class="pill">完整 HTML 界面参考</span><h1>界面参考页</h1><p>这个页面用于集中查看视觉样式，不用逐个走完整业务流程。这里包含头图、表单、数据表、状态提示、指标卡和流程块。</p></section><section class="grid"><div class="card"><div class="section-title"><h3>提示状态</h3></div><div class="alert success">成功提示示例</div><div class="alert info">信息提示示例</div><div class="alert error">错误提示示例</div></div><div class="card"><div class="section-title"><h3>指标卡</h3></div><div class="grid"><div class="kpi"><div class="small">已配置域名</div><div class="metric">1</div></div><div class="kpi"><div class="small">未绑定卡密</div><div class="metric">128</div></div><div class="kpi"><div class="small">OIDC 端点数</div><div class="metric">5</div></div></div></div><div class="card"><div class="section-title"><h3>表单样式</h3></div><div class="form-grid"><div class="field"><label>邮箱前缀</label><input type="text" value="alice"></div><div class="field"><label>邮箱后缀</label><input type="text" value="example.com"></div><div class="field"><label>卡密</label><input type="text" value="AB12CD-EF34GH-IJ56KL-MN78OP"></div><div class="field"><label>OpenAI 回调白名单</label><input type="text" value="https://chatgpt.com/"></div></div><div class="actions" style="margin-top:14px"><button class="inline" type="button">继续</button><button class="inline secondary" type="button">取消</button></div></div></section><section class="card"><div class="section-title"><h3>数据表样式</h3></div><div class="table-wrap"><table><tr><th>ID</th><th>邮箱</th><th>状态</th><th>操作</th></tr><tr><td>12</td><td>alice@example.com</td><td><span class="badge">启用</span></td><td><button class="inline secondary" type="button">禁用</button></td></tr><tr><td>13</td><td>bob@example.com</td><td><span class="badge">停用</span></td><td><button class="inline warn" type="button">恢复</button></td></tr></table></div></section>';
}

function app_install_html($csrf, $recovery = false, array $config = [])
{
    if ($recovery) {
        return '<div class="center-shell"><section class="install-hero"><span class="pill">恢复模式</span><h1>恢复首个管理员</h1><p>系统配置仍然存在，但当前没有找到管理员账号。请重新创建一个拥有者管理员以恢复控制。</p></section><section class="card"><form method="post" action="/install" class="stack"><input type="hidden" name="csrf_token" value="' . app_h($csrf) . '"><div class="form-grid"><div class="field"><label>管理员用户名</label><input type="text" name="admin_username" required></div><div class="field"><label>管理员邮箱</label><input type="email" name="admin_email" required></div><div class="field"><label>管理员密码</label><input type="password" name="admin_password" required></div></div><div class="actions"><button type="submit">创建恢复管理员</button></div></form></section></div>';
    }

    return '<div class="center-shell"><section class="install-hero"><span class="pill">第 1 步，共 1 步</span><h1>安装 GPT OIDC</h1><p>这个安装界面会自动写入 <code>app/config.php</code>、导入 MySQL 表结构、生成 OIDC 签名密钥，并创建首个管理员账号。新服务器首次部署只需要执行一次。</p></section><section class="card"><div class="alert info"><strong>先说明：</strong> 你现在看到的是<strong>你自己系统</strong>的安装页，不是 OpenAI 后台的 OIDC 向导页。<br>OpenAI 后台里做的是：<code>Provide an Identity Provider Name</code>、<code>Create an Application</code>、<code>Add Claims</code>、<code>Provide your OIDC Configuration</code>、<code>Configure Application Link</code>、<code>Test Single Sign-On</code>。<br>本安装页这里只保存 OpenAI 最终给你的 <code>Client ID</code>、<code>Client Secret</code> 和 <code>Login redirect URI</code> 白名单。</div><form method="post" action="/install" class="stack"><input type="hidden" name="csrf_token" value="' . app_h($csrf) . '"><div class="section-title"><h3>应用配置</h3></div><div class="form-grid"><div class="field"><label>应用地址</label><input type="url" name="app_url" placeholder="https://sso.example.com" value="' . app_h(isset($config['app_url']) ? $config['app_url'] : '') . '" required><div class="hint">这里填用户浏览器真正访问到的外网地址，例如 <code>https://sso.example.com</code>。不要填服务器本地路径，不要填 <code>/public</code> 或 <code>/pubilc</code>，也不要少写 <code>https://</code>。</div></div><div class="field"><label>允许的邮箱后缀</label><input type="text" name="allowed_email_domains" placeholder="example.com,example.org" value="' . app_h(isset($config['allowed_email_domains']) ? implode(', ', (array) $config['allowed_email_domains']) : '') . '" required><div class="hint">多个后缀用逗号分隔，只有这些后缀可以通过 `/sso` 登录。</div></div><div class="field"><label>WebUI API Key</label><input class="mono" type="text" name="api_key" value="' . app_h(isset($config['api_key']) ? $config['api_key'] : '') . '" placeholder="留空则自动生成"><div class="hint">这里是 WebUI 调用 <code>/api/cards/generate</code> 的 Bearer Token。留空会自动生成，安装后可在 <code>app/config.php</code> 复制到 WebUI 的 <code>SUB2API_OIDC_API_KEY</code>。</div></div></div><div class="section-title"><h3>数据库</h3></div><div class="form-grid"><div class="field"><label>数据库主机</label><input type="text" name="db_host" value="' . app_h(isset($config['db_host']) ? $config['db_host'] : '127.0.0.1') . '" required></div><div class="field"><label>数据库端口</label><input type="number" name="db_port" value="' . app_h(isset($config['db_port']) ? $config['db_port'] : 3306) . '" required></div><div class="field"><label>数据库名</label><input type="text" name="db_name" value="' . app_h(isset($config['db_name']) ? $config['db_name'] : '') . '" required></div><div class="field"><label>数据库用户名</label><input type="text" name="db_user" value="' . app_h(isset($config['db_user']) ? $config['db_user'] : '') . '" required></div><div class="field"><label>数据库密码</label><input type="password" name="db_pass"></div></div><div class="section-title"><h3>OpenAI OIDC 占位配置</h3></div><div class="alert info"><strong>这里要填的只有三类值：</strong><br>1. OpenAI 向导生成的 <code>Client ID</code><br>2. OpenAI 向导生成的 <code>Client Secret</code><br>3. OpenAI 向导里那条 <code>Login redirect URI</code>，填到下面的回调白名单里</div><div class="form-grid"><div class="field"><label>OpenAI 客户端 ID</label><input type="text" name="oidc_client_id" value="' . app_h(isset($config['oidc_client_id']) ? $config['oidc_client_id'] : '') . '" placeholder="OpenAI 后台生成后再填"></div><div class="field"><label>OpenAI 客户端 Secret</label><input type="text" name="oidc_client_secret" value="' . app_h(isset($config['oidc_client_secret']) ? $config['oidc_client_secret'] : '') . '" placeholder="OpenAI 后台生成后再填"></div><div class="field"><label>OpenAI 回调白名单（Login redirect URI）</label><textarea name="oidc_redirect_uris" placeholder="每行一个 OpenAI 提供的 Login redirect URI">' . app_h(isset($config['oidc_allowed_redirect_uris']) ? implode("\n", (array) $config['oidc_allowed_redirect_uris']) : '') . '</textarea><div class="hint">注意：这里不是填你自己的域名回调，而是填 OpenAI 向导里给你的那条 Login redirect URI，每行一个，必须精确匹配。</div></div></div><div class="section-title"><h3>首个管理员</h3></div><div class="form-grid"><div class="field"><label>管理员用户名</label><input type="text" name="admin_username" required></div><div class="field"><label>管理员邮箱</label><input type="email" name="admin_email" required></div><div class="field"><label>管理员密码</label><input type="password" name="admin_password" required></div></div><div class="actions"><button type="submit">立即安装</button></div></form></section></div>';
}

function app_settings_form_html(array $config, $csrf)
{
    $domains = implode(', ', (array) $config['allowed_email_domains']);
    $redirects = implode("\n", (array) $config['oidc_allowed_redirect_uris']);

    return '<div class="card"><div class="section-title"><h3>系统设置</h3><span class="badge">会写入 app/config.php</span></div><div class="alert info"><strong>说明：</strong> OpenAI 后台的应用创建、声明配置、应用链接配置不在这里做。<br>这里仅用于保存 OpenAI 最终生成的 <code>Client ID</code>、<code>Client Secret</code> 和 <code>Login redirect URI</code> 白名单。</div><form method="post" action="/admin/settings/save" class="stack"><input type="hidden" name="csrf_token" value="' . app_h($csrf) . '"><div class="form-grid"><div class="field"><label>应用地址</label><input type="url" name="app_url" value="' . app_h($config['app_url']) . '" required></div><div class="field"><label>允许的邮箱后缀</label><input type="text" name="allowed_email_domains" value="' . app_h($domains) . '" required></div><div class="field"><label>OIDC Issuer</label><input type="url" name="oidc_issuer" value="' . app_h($config['oidc_issuer']) . '" required></div><div class="field"><label>WebUI API Key</label><input class="mono" type="text" name="api_key" value="' . app_h(isset($config['api_key']) ? $config['api_key'] : '') . '"><div class="hint">复制到 WebUI 的 <code>SUB2API_OIDC_API_KEY</code>。修改后 WebUI 侧也要同步更新。</div></div><div class="field"><label>OIDC 客户端 ID</label><input type="text" name="oidc_client_id" value="' . app_h($config['oidc_client_id']) . '"></div><div class="field"><label>OIDC 客户端 Secret</label><input type="text" name="oidc_client_secret" value="' . app_h($config['oidc_client_secret']) . '"></div><div class="field"><label>Access Token 有效期</label><input type="number" name="oidc_access_token_ttl" value="' . app_h($config['oidc_access_token_ttl']) . '" min="60" required></div><div class="field"><label>ID Token 有效期</label><input type="number" name="oidc_id_token_ttl" value="' . app_h($config['oidc_id_token_ttl']) . '" min="60" required></div><div class="field"><label>授权码有效期</label><input type="number" name="oidc_auth_code_ttl" value="' . app_h($config['oidc_auth_code_ttl']) . '" min="30" required></div></div><div class="field"><label>OpenAI 回调白名单（Login redirect URI）</label><textarea name="oidc_redirect_uris" required>' . app_h($redirects) . '</textarea><div class="hint">每行一个 OpenAI 后台生成的 Login redirect URI，必须精确匹配。不要在这里填你自己的域名地址。</div></div><div class="actions"><button type="submit">保存设置</button></div></form></div>';
}
